-- ============================================================================
-- Zephyriov migration 2026-07-20: curated opening lines
-- (generated by scripts/generate-seed.mjs — do not edit by hand)
--
-- Syncs a live database to the audited catalog (see README 'Metodología de
-- curaduría'). By (opening slug, rank):
--   1. deletes lines removed from the catalog (cascade removes their moves,
--      SRS cards and session history),
--   2. inserts lines that don't exist yet,
--   3. syncs line names,
--   4. replaces all moves of lines whose SAN sequence changed,
--   5. syncs explanations of unchanged lines in place,
--   6. resets the SRS cards of changed lines (state='new', interval 0,
--      unlocked_moves back to the user's moves_per_block) — the memorized
--      content changed, so scheduling must restart,
--   7. creates missing cards for users already studying an opening.
--
-- Idempotent: safe to paste more than once (second run changes nothing).
-- ============================================================================
begin;

create temp table _catalog (
  slug text, rank smallint, line_name text, ply smallint, san text, explanation text
) on commit drop;


-- Lines whose move sequence differs from the catalog (or that are missing).
create temp table _changed on commit drop as
select c.slug, c.rank
from (select distinct slug, rank from _catalog) c
join public.openings o on o.slug = c.slug
left join public.opening_lines ol on ol.opening_id = o.id and ol.rank = c.rank
where ol.id is null
   or (select string_agg(lm.san, ' ' order by lm.ply)
       from public.line_moves lm where lm.line_id = ol.id)
      is distinct from
      (select string_agg(c2.san, ' ' order by c2.ply)
       from _catalog c2 where c2.slug = c.slug and c2.rank = c.rank);

-- 1. delete lines removed from the catalog
delete from public.opening_lines ol
using public.openings o
where o.id = ol.opening_id
  and not exists (select 1 from _catalog c where c.slug = o.slug and c.rank = ol.rank);

-- 2. insert lines new to the database
select o.id, c.line_name, c.rank
from (select distinct slug, rank, line_name from _catalog) c
join public.openings o on o.slug = c.slug
on conflict (opening_id, rank) do nothing;

-- 3. sync line names
update public.opening_lines ol
set name = c.line_name
from public.openings o,
     (select distinct slug, rank, line_name from _catalog) c
where ol.opening_id = o.id and o.slug = c.slug and ol.rank = c.rank
  and ol.name is distinct from c.line_name;

-- 4. replace the moves of changed lines
delete from public.line_moves lm
using public.opening_lines ol, public.openings o, _changed ch
where lm.line_id = ol.id and ol.opening_id = o.id
  and o.slug = ch.slug and ol.rank = ch.rank;

select ol.id, c.ply, c.san, c.explanation
from _catalog c
join _changed ch on ch.slug = c.slug and ch.rank = c.rank
join public.openings o on o.slug = c.slug
join public.opening_lines ol on ol.opening_id = o.id and ol.rank = c.rank;

-- 5. sync explanations of unchanged lines
update public.line_moves lm
set explanation = c.explanation
from public.opening_lines ol, public.openings o, _catalog c
where lm.line_id = ol.id and ol.opening_id = o.id
  and o.slug = c.slug and ol.rank = c.rank and lm.ply = c.ply
  and lm.explanation is distinct from c.explanation;

-- 6. reset SRS cards of changed lines
update public.user_lines ul
set state = 'new', interval_days = 0, due_date = current_date,
    reps = 0, lapses = 0, last_result = null,
    unlocked_moves = p.moves_per_block
from public.profiles p, public.opening_lines ol, public.openings o, _changed ch
where p.user_id = ul.user_id
  and ul.line_id = ol.id and ol.opening_id = o.id
  and o.slug = ch.slug and ol.rank = ch.rank;

-- 7. create missing cards for openings users already study
select uo.user_id, ol.id, p.moves_per_block
from public.user_openings uo
join public.opening_lines ol on ol.opening_id = uo.opening_id
join public.profiles p on p.user_id = uo.user_id
where uo.is_active
on conflict (user_id, line_id) do nothing;

commit;
